import React from 'react';
import { FormMode, isEditingMode } from '../form/FormMode';
import styles from './VoucherFormToolbar.module.css';

/** @deprecated Use FormMode from `components/form` */
export type VoucherFormMode = FormMode;

/** Tooltip khi nút disabled — `title` hiển thị lý do (hover). */
export interface VoucherToolbarDisabledReasons {
  approve?: string;
  post?: string;
  copy?: string;
  print?: string;
  edit?: string;
  delete?: string;
}

function toolbarButtonTitle(enabled: boolean, enabledTitle: string, disabledReason?: string): string {
  if (!enabled && disabledReason?.trim()) return disabledReason.trim();
  return enabledTitle;
}

export interface VoucherFormToolbarProps {
  testIdPrefix: string;
  title: string;
  /** Pill Mức xử lý — `VoucherFormStatusGroup`. Cấm badge `status` / `VoucherStatusBadge`. */
  processingLevelBadge?: React.ReactNode;
  formMode: FormMode;
  showViewHint?: boolean;
  canApprove?: boolean;
  canPost?: boolean;
  /** false — không render nút Ghi sổ (mức xử lý 9). */
  showPostButton?: boolean;
  canCopy?: boolean;
  canPrint?: boolean;
  canEdit?: boolean;
  canDelete?: boolean;
  saving?: boolean;
  posting?: boolean;
  saveLabel?: string;
  searchNav?: {
    index: number;
    total: number;
    onFirst: () => void;
    onPrev: () => void;
    onNext: () => void;
    onEnd: () => void;
  };
  onBack: () => void;
  onApprove: () => void;
  onPost: () => void;
  onCopy: () => void;
  onPrint: () => void;
  onSearch: () => void;
  onNew: () => void;
  onEdit: () => void;
  onSave: () => void;
  onCancel: () => void;
  onDelete: () => void;
  /** Lý do disable — hiển thị qua `title` khi hover (rule `voucher-form-toolbar.md`). */
  disabledReasons?: VoucherToolbarDisabledReasons;
}

export const VoucherFormToolbar: React.FC<VoucherFormToolbarProps> = ({
  testIdPrefix,
  title,
  processingLevelBadge,
  formMode,
  showViewHint,
  canApprove = false,
  canPost = false,
  showPostButton = true,
  canCopy = false,
  canPrint = false,
  canEdit = false,
  canDelete = false,
  saving = false,
  posting = false,
  saveLabel = 'Lưu',
  searchNav,
  onBack,
  onApprove,
  onPost,
  onCopy,
  onPrint,
  onSearch,
  onNew,
  onEdit,
  onSave,
  onCancel,
  onDelete,
  disabledReasons,
}) => {
  const tid = (s: string) => `${testIdPrefix}-toolbar-${s}`;
  const isEditing = isEditingMode(formMode);
  const hasNav = !isEditing && searchNav && searchNav.total > 0;
  const navAtStart = hasNav && searchNav.index <= 0;
  const navAtEnd = hasNav && searchNav.index >= searchNav.total - 1;

  return (
    <>
      <div className={styles.toolbar} data-testid={tid('bar')}>
        <div className={styles.toolbarGroup} data-testid={tid('left')}>
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('back')}
            onClick={onBack}
          >
            <i className="fas fa-arrow-left" /> Quay lại
          </button>
          {!isEditing && (
            <>
              <button
                type="button"
                className={styles.toolbarBtn}
                data-testid={tid('approve')}
                onClick={onApprove}
                disabled={!canApprove}
                title={toolbarButtonTitle(
                  !!canApprove,
                  'Phê duyệt — cập nhật mức xử lý',
                  disabledReasons?.approve,
                )}
              >
                <i className="fas fa-check-double" /> Phê duyệt
              </button>
              {showPostButton && (
                <button
                  type="button"
                  className={styles.toolbarBtn}
                  data-testid={tid('post')}
                  onClick={onPost}
                  disabled={!canPost || posting}
                  title={toolbarButtonTitle(
                    !!(canPost && !posting),
                    'Ghi sổ chứng từ',
                    disabledReasons?.post,
                  )}
                >
                  <i className={`fas ${posting ? 'fa-spinner fa-spin' : 'fa-book'}`} /> Ghi sổ
                </button>
              )}
              <button
                type="button"
                className={styles.toolbarBtn}
                data-testid={tid('copy')}
                onClick={onCopy}
                disabled={!canCopy}
                title={toolbarButtonTitle(!!canCopy, 'Sao chép chứng từ', disabledReasons?.copy)}
              >
                <i className="fas fa-copy" /> Copy
              </button>
              <button
                type="button"
                className={styles.toolbarBtn}
                data-testid={tid('print')}
                onClick={onPrint}
                disabled={!canPrint}
                title={toolbarButtonTitle(!!canPrint, 'In chứng từ', disabledReasons?.print)}
              >
                <i className="fas fa-print" /> In
              </button>
              <button
                type="button"
                className={styles.toolbarBtn}
                data-testid={tid('search')}
                onClick={onSearch}
                title="Tìm kiếm chứng từ"
              >
                <i className="fas fa-search" /> Tìm kiếm
              </button>
              {hasNav && (
                <div className={styles.navGroup} data-testid={tid('search-nav')}>
                  <button
                    type="button"
                    className={styles.navBtn}
                    data-testid={tid('search-first')}
                    onClick={searchNav.onFirst}
                    disabled={navAtStart}
                    title="Chứng từ đầu"
                  >
                    <i className="fas fa-angle-double-left" />
                  </button>
                  <button
                    type="button"
                    className={styles.navBtn}
                    data-testid={tid('search-prev')}
                    onClick={searchNav.onPrev}
                    disabled={navAtStart}
                    title="Chứng từ trước"
                  >
                    <i className="fas fa-angle-left" />
                  </button>
                  <span className={styles.navPosition} data-testid={tid('search-position')}>
                    {searchNav.index + 1}/{searchNav.total}
                  </span>
                  <button
                    type="button"
                    className={styles.navBtn}
                    data-testid={tid('search-next')}
                    onClick={searchNav.onNext}
                    disabled={navAtEnd}
                    title="Chứng từ sau"
                  >
                    <i className="fas fa-angle-right" />
                  </button>
                  <button
                    type="button"
                    className={styles.navBtn}
                    data-testid={tid('search-end')}
                    onClick={searchNav.onEnd}
                    disabled={navAtEnd}
                    title="Chứng từ cuối"
                  >
                    <i className="fas fa-angle-double-right" />
                  </button>
                </div>
              )}
            </>
          )}
        </div>

        <div className={styles.toolbarGroup} data-testid={tid('right')}>
          {isEditing ? (
            <>
              <button
                type="button"
                className={styles.toolbarBtn}
                data-testid={tid('cancel')}
                onClick={onCancel}
                disabled={saving}
                title="Hủy thay đổi"
              >
                <i className="fas fa-times" /> Hủy
              </button>
              <button
                type="button"
                className={styles.toolbarBtnPrimary}
                data-testid={tid('save')}
                onClick={onSave}
                disabled={saving}
                title="Lưu chứng từ"
              >
                <i className={`fas ${saving ? 'fa-spinner fa-spin' : 'fa-save'}`} /> {saveLabel}
              </button>
            </>
          ) : (
            <>
              <button
                type="button"
                className={styles.toolbarBtn}
                data-testid={tid('new')}
                onClick={onNew}
                title="Tạo chứng từ mới"
              >
                <i className="fas fa-plus" /> Tạo mới
              </button>
              <button
                type="button"
                className={styles.toolbarBtn}
                data-testid={tid('edit')}
                onClick={onEdit}
                disabled={!canEdit}
                title={toolbarButtonTitle(!!canEdit, 'Sửa chứng từ', disabledReasons?.edit)}
              >
                <i className="fas fa-edit" /> Sửa
              </button>
              <button
                type="button"
                className={styles.toolbarBtnDanger}
                data-testid={tid('delete')}
                onClick={onDelete}
                disabled={!canDelete}
                title={toolbarButtonTitle(!!canDelete, 'Xóa chứng từ', disabledReasons?.delete)}
              >
                <i className="fas fa-trash-alt" /> Xóa
              </button>
            </>
          )}
        </div>
      </div>

      <div className={styles.titleBlock}>
        <div className={styles.titleRow}>
          <h1 className={styles.title} data-testid={tid('title')}>{title}</h1>
          {processingLevelBadge}
        </div>
        {showViewHint && formMode === FormMode.View && (
          <div className={styles.viewModeHint} data-testid={tid('view-hint')}>
            <i className="fas fa-eye" /> Chế độ xem — nhấn <strong>Sửa</strong> để chỉnh sửa
          </div>
        )}
        {isEditing && (
          <div className={styles.readOnlyHint} data-testid={tid('edit-hint')}>
            <i className="fas fa-pen" /> Đang {formMode === FormMode.Create ? 'tạo mới' : 'chỉnh sửa'} — Lưu hoặc Hủy
          </div>
        )}
      </div>
    </>
  );
};

