import type { VoucherToolbarDisabledReasons } from '../components/voucher/VoucherFormToolbar';

/** Mức xử lý cuối (phê duyệt + hoạch toán) — `voucher-setup-master.md` · `voucher-form-toolbar.md`. */
export const VOUCHER_FINAL_PROCESSING_LEVEL = '9';

export function isFinalProcessingLevel(level: string | undefined | null): boolean {
  return String(level ?? '').trim() === VOUCHER_FINAL_PROCESSING_LEVEL;
}

/** Toolbar **Ghi sổ** — ẩn khi mức 9 (đã hoàn tất quy trình phê duyệt). */
export function canVoucherToolbarPost(status: string, processingLevel: string): boolean {
  if (isFinalProcessingLevel(processingLevel)) return false;
  return status === 'Draft';
}

/** Form read-only — Posted/Cancelled hoặc mức 9. */
export function isVoucherFormStatusLocked(status: string, processingLevel: string): boolean {
  if (status === 'Cancelled' || status === 'Posted') return true;
  return isFinalProcessingLevel(processingLevel);
}

/** Tooltip nút toolbar disabled — dùng chung mọi form chứng từ (`voucher-form-toolbar.md`). */
export function buildVoucherToolbarDisabledReasons(input: {
  isNew: boolean;
  status: string;
  showPostButton: boolean;
  isStatusLocked: boolean;
  draftOnlyMessage?: string;
}): VoucherToolbarDisabledReasons {
  const draftOnly =
    input.status !== 'Draft'
      ? (input.draftOnlyMessage ?? 'Chỉ thao tác trên chứng từ ở trạng thái Nháp')
      : undefined;
  return {
    approve: input.isNew ? 'Lưu chứng từ trước khi phê duyệt' : draftOnly,
    post: input.isNew
      ? 'Lưu chứng từ trước khi ghi sổ'
      : !input.showPostButton
        ? 'Đã đạt mức xử lý cuối hoặc chứng từ không còn Nháp'
        : draftOnly,
    copy: input.isNew ? 'Lưu chứng từ trước khi sao chép' : undefined,
    print: input.isNew ? 'Lưu chứng từ trước khi in' : undefined,
    edit: input.isStatusLocked ? 'Chỉ xem — đã ghi sổ hoặc mức xử lý cuối' : undefined,
    delete: input.isNew ? undefined : input.status !== 'Draft' ? 'Chỉ xóa chứng từ Nháp' : undefined,
  };
}
